using System;using System.Linq;using System.Windows;using System.Windows.Controls;using System.Windows.Media;
namespace Tgirrr.CadLisp {
 public sealed class CopySequenceWindow:Window {
  readonly string original;readonly ComboBox part=Combo(),kind=Combo(),ending=Combo();readonly TextBox step=Box("1"),values=Box("ĐỎ;VÀNG;XANH"),preview=Box("");readonly TextBlock valuesLabel=Label("Danh sách (; hoặc xuống dòng)");internal SequenceSettings Settings;
  public CopySequenceWindow(string text){original=text;Title="TGIRR — Copy theo quy luật";Width=620;Height=430;MinWidth=580;MinHeight=400;WindowStartupLocation=WindowStartupLocation.CenterScreen;ResizeMode=ResizeMode.CanResizeWithGrip;Background=new SolidColorBrush(Color.FromRgb(36,45,57));Foreground=Brushes.White;FontFamily=new FontFamily("Segoe UI");var root=new Grid{Margin=new Thickness(14)};root.ColumnDefinitions.Add(new ColumnDefinition{Width=new GridLength(1.08,GridUnitType.Star)});root.ColumnDefinitions.Add(new ColumnDefinition{Width=new GridLength(1,GridUnitType.Star)});root.RowDefinitions.Add(new RowDefinition{Height=GridLength.Auto});root.RowDefinitions.Add(new RowDefinition());root.RowDefinitions.Add(new RowDefinition{Height=GridLength.Auto});Content=root;var title=new TextBlock{Text="COPY THEO QUY LUẬT",FontSize=14,FontWeight=FontWeights.SemiBold,Foreground=new SolidColorBrush(Color.FromRgb(86,190,232)),Margin=new Thickness(0,0,0,7)};Grid.SetColumnSpan(title,2);root.Children.Add(title);var left=new Grid{Margin=new Thickness(0,0,9,0)};left.ColumnDefinitions.Add(new ColumnDefinition());for(int i=0;i<6;i++)left.RowDefinitions.Add(new RowDefinition{Height=GridLength.Auto});Grid.SetRow(left,1);root.Children.Add(left);AddField(left,0,0,"Nội dung gốc",Box(text,true));AddField(left,1,0,"Thành phần tăng",part);AddField(left,2,0,"Kiểu quy luật",kind);AddField(left,3,0,"Bước tăng",step);AddField(left,4,0,valuesLabel,values);AddField(left,5,0,"Khi hết danh sách",ending);var right=new StackPanel{Margin=new Thickness(9,0,0,0)};Grid.SetRow(right,1);Grid.SetColumn(right,1);root.Children.Add(right);right.Children.Add(Label("Xem trước 5 giá trị"));preview.IsReadOnly=true;preview.AcceptsReturn=true;preview.VerticalScrollBarVisibility=ScrollBarVisibility.Auto;preview.Height=260;preview.Background=new SolidColorBrush(Color.FromRgb(27,36,48));preview.Foreground=new SolidColorBrush(Color.FromRgb(220,232,242));right.Children.Add(preview);var actionRow=new StackPanel{Orientation=Orientation.Horizontal,HorizontalAlignment=HorizontalAlignment.Right,Margin=new Thickness(0,8,0,0)};Grid.SetRow(actionRow,2);Grid.SetColumnSpan(actionRow,2);root.Children.Add(actionRow);var button=new Button{Content="BẮT ĐẦU COPY",Width=150,Padding=new Thickness(10,7,10,7),FontWeight=FontWeights.SemiBold,Background=new SolidColorBrush(Color.FromRgb(58,118,162)),Foreground=Brushes.White};button.Click+=(s,e)=>{if(Build(true)){DialogResult=true;Close();}};actionRow.Children.Add(button);part.ItemsSource=CopySequenceService.Parts(text);part.SelectedIndex=0;kind.ItemsSource=new[]{"Số","Chữ A–Z","Danh sách tùy chỉnh"};kind.SelectedIndex=part.SelectedItem is SequencePart x&&x.Numeric?0:1;ending.ItemsSource=new[]{"Dừng khi hết","Quay vòng","Giữ giá trị cuối"};ending.SelectedIndex=0;foreach(var c in new[]{part,kind,ending})c.SelectionChanged+=(s,e)=>RefreshView();step.TextChanged+=(s,e)=>RefreshView();values.TextChanged+=(s,e)=>RefreshView();Loaded+=(s,e)=>RefreshView();}
  static ComboBox Combo()=>new ComboBox{Margin=new Thickness(0,1,5,5),Padding=new Thickness(5,3,5,3)};static TextBox Box(string text,bool readOnly=false)=>new TextBox{Text=text,IsReadOnly=readOnly,Margin=new Thickness(0,1,5,5),Padding=new Thickness(5,3,5,3)};static TextBlock Label(string text)=>new TextBlock{Text=text,Margin=new Thickness(0,0,5,1)};static void AddField(Grid grid,int row,int column,string label,Control control){AddField(grid,row,column,Label(label),control);}static void AddField(Grid grid,int row,int column,TextBlock label,Control control){var panel=new StackPanel{Margin=new Thickness(0,0,5,0)};panel.Children.Add(label);panel.Children.Add(control);Grid.SetRow(panel,row);Grid.SetColumn(panel,column);grid.Children.Add(panel);}
  bool Build(bool showError){if(!(part.SelectedItem is SequencePart selected))return false;if(!int.TryParse(step.Text,out int amount)||amount<1){if(showError)MessageBox.Show("Bước tăng phải là số nguyên dương.");return false;}var vals=values.Text.Split(new[]{';','\r','\n'},StringSplitOptions.RemoveEmptyEntries).Select(v=>v.Trim()).Where(v=>v.Length>0).ToArray();Settings=new SequenceSettings{Part=selected,Kind=(SequenceKind)Math.Max(0,kind.SelectedIndex),Step=amount,Values=vals,End=(CustomEnd)Math.Max(0,ending.SelectedIndex)};return true;}void RefreshView(){bool custom=kind.SelectedIndex==(int)SequenceKind.Custom;values.Visibility=valuesLabel.Visibility=custom?Visibility.Visible:Visibility.Collapsed;ending.Visibility=custom?Visibility.Visible:Visibility.Collapsed;if(!Build(false)){preview.Text="";return;}preview.Text=string.Join(Environment.NewLine,Enumerable.Range(1,5).Select(i=>CopySequenceService.Apply(original,Settings,i)??"(Dừng)"));}
 }
}
